import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        assertEquals("a2b3c1", new Solution().compressRunLength("aabbbc"));
    }

    @Test
    void allUnique() {
        // every char appears once
        assertEquals("a1b1c1d1", new Solution().compressRunLength("abcd"));
    }

    @Test
    void allSame() {
        assertEquals("a4", new Solution().compressRunLength("aaaa"));
    }

    @Test
    void alternating() {
        // runs restart each time the character changes
        assertEquals("a2b2a2b2", new Solution().compressRunLength("aabbaabb"));
    }

    @Test
    void singleChar() {
        assertEquals("a1", new Solution().compressRunLength("a"));
    }

    @Test
    void empty() {
        assertEquals("", new Solution().compressRunLength(""));
    }

    @Test
    void longerRun() {
        assertEquals("x1y5z2", new Solution().compressRunLength("xyyyyyzz"));
    }
}
